// Node: Activar Pausa
// v3 (2026-05-04): mega audit fixes
// - Save state_before_handoff
// - Differentiate business hours response
// - Notify operator with lead context
const SHEET_URL = 'https://script.google.com/macros/s/AKfycbzeuKlW54ENFAxqc3cXF1nGJwAyudHR2xWbLTV8tXMCUvsJdEq5zwxyaW_ddY7pOaYV/exec';
const sd = $getWorkflowStaticData('global');
if (!sd.leads) sd.leads = {};

let phone = '';
try { phone = $('Parsear Mensaje').first().json.phoneNorm || $('Parsear Mensaje').first().json.phone || ''; } catch(_) {}
phone = String(phone).replace(/[^0-9]/g, '');

const now = new Date().toISOString();
const isBusinessHours = $('Parsear Mensaje').first().json.isBusinessHours || false;

if (phone) {
  if (!sd.leads[phone]) {
    sd.leads[phone] = { phone, messageCount: 0, state: 'NEW', firstContact: now, conversationHistory: [] };
  }
  const lead = sd.leads[phone];
  // SAVE state before handoff
  lead.state_before_handoff = lead.state;
  lead.BotPausado     = 'SI';
  lead.PausaTimestamp  = now;
  lead.UltimoHumanoTS  = now;
  lead.state           = 'HANDOFF';

  const leadContext = 'State: ' + (lead.state_before_handoff || 'NEW') + ', Msgs: ' + (lead.messageCount || 0) + ', Name: ' + (lead.profileName || '?');

  try {
    await $helpers.httpRequest({
      method: 'POST', url: SHEET_URL,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        fecha: now, telefono: phone, nombre: lead.profileName || '', pais: lead._country || '',
        estado: 'HANDOFF',
        mensaje: '[BOT PAUSADO — usuario pide hablar con humano] ' + leadContext,
        rol: 'sistema', por_que_llego: '', intereses: '', edad_hijo: lead._childAge || '', fuente: 'pausa_manual'
      })
    });
  } catch(e) { console.log('[Activar Pausa] Sheets err:', e.message); }

  // Notify operator with context
  try {
    await $helpers.httpRequest({
      method: 'POST', url: 'https://api.ycloud.com/v2/whatsapp/messages',
      headers: { 'X-API-Key': 'b0bdbae389901432af2b47d9c6a4dcbe', 'Content-Type': 'application/json' },
      body: JSON.stringify({
        from: '56964754219', to: '56971360895', type: 'text',
        text: { body: '\ud83d\udc64 Lead pide humano: ' + phone + ' (' + (lead.profileName || '?') + ')\n' + leadContext + '\n' + (isBusinessHours ? 'EN horario laboral' : 'FUERA de horario') }
      })
    });
  } catch(e) {}
}
console.log('[Activar Pausa] phone=' + phone + ' pausado=SI');
return $input.all();

