function breakLine(line) {
  if (line.length <= 90) return [line];
  let cut = line.lastIndexOf('. ', 88);
  if (cut > 40) return [line.slice(0, cut + 1), line.slice(cut + 2).trim()];
  cut = line.lastIndexOf('? ', 88);
  if (cut > 40) return [line.slice(0, cut + 1), line.slice(cut + 2).trim()];
  cut = line.lastIndexOf(', ', 85);
  if (cut > 40) return [line.slice(0, cut + 1), line.slice(cut + 2).trim()];
  cut = line.lastIndexOf(' ', 88);
  if (cut > 40) return [line.slice(0, cut), line.slice(cut + 1).trim()];
  return [line.slice(0, 90)];
}

