// Node: Parsear Mensaje
// v3: +/startbot, +video detection, +isNonActionable, +document payment hints
const body = $input.first().json?.body ?? {};
const msg = body.whatsappInboundMessage;
const outMsg = body.whatsappMessage;

const IK_NUMBER = '56964754219';
const now = new Date();
const chileOffset = (now.getUTCMonth() >= 3 && now.getUTCMonth() <= 8) ? 4 : 3;
const chileHour = (now.getUTCHours() - chileOffset + 24) % 24;
const isBusinessHours = chileHour >= 8 && chileHour < 22;

// --- HUMAN TAKEOVER detection ---
let isHumanTakeover = false;
let takeoverPhone = '';
let humanText = '';
if (outMsg && outMsg.from === IK_NUMBER && outMsg.to) {
  isHumanTakeover = true;
  takeoverPhone = outMsg.to;
  humanText = (outMsg.text && outMsg.text.body) || outMsg.body || '';
}

if (!msg && !isHumanTakeover) {
  return [{ json: {
    phone: 'unknown', toNumber: 'unknown', msgId: 'system-event',
    profileName: 'System', type: 'text', content: 'System Event',
    mediaId: null, audioUrl: null, imageUrl: null,
    isBusinessHours, isSpam: true, requestsHuman: false,
    isHumanTakeover: false, takeoverPhone: '',
    isStopCmd: false, isStartCmd: false, isChild: false, siblingCount: 1,
    isNonActionable: true
  }}];
}

if (isHumanTakeover) {
  const isStopCmd = /\b(\/stopbot|\/bot\s*off|\/pausa|\/mute)\b/i.test(humanText);
  const isStartCmd = /\b(\/startbot|\/bot\s*on|\/reanudar|\/unmute)\b/i.test(humanText);
  return [{ json: {
    phone: takeoverPhone, toNumber: IK_NUMBER, msgId: outMsg.id || 'takeover',
    profileName: 'HumanAgent', type: 'text', content: humanText,
    mediaId: null, audioUrl: null, imageUrl: null,
    isBusinessHours: true, isSpam: false, requestsHuman: false,
    isHumanTakeover: true, takeoverPhone: takeoverPhone,
    isStopCmd, isStartCmd, isChild: false, siblingCount: 1,
    isNonActionable: false
  }}];
}

// --- Mensaje inbound normal ---
let type = 'text', content = '', mediaId = null, audioUrl = null, imageUrl = null, isSpam = false;

if (msg.type === 'interactive' || msg.interactive) {
  type = 'text';
  const inter = msg.interactive || {};
  if (inter.button_reply)      content = inter.button_reply.title || inter.button_reply.id || '';
  else if (inter.list_reply)   content = inter.list_reply.title   || inter.list_reply.id   || '';
  else                          content = JSON.stringify(inter);
} else if (msg.text) {
  type = 'text';
  content = msg.text.body || '';
} else if (msg.audio || msg.voice) {
  type = 'audio';
  const a = msg.audio || msg.voice;
  mediaId = a.id || null;
  audioUrl = a.link || null;
} else if (msg.image) {
  type = 'image';
  mediaId = msg.image.id || null;
  imageUrl = msg.image.link || null;
  content = msg.image.caption || '';
} else if (msg.video) {
  // FIX: Video detection (was falling to else block)
  type = 'text';
  content = '[Video recibido' + (msg.video.caption ? ': ' + msg.video.caption : '') + ']';
} else if (msg.document) {
  type = 'text';
  const fname = (msg.document.filename || 'archivo').toLowerCase();
  // Detect payment-related documents
  const isPaymentDoc = /comprobante|pago|transfer|recibo|deposito|voucher/i.test(fname);
  content = '[Documento recibido: ' + (msg.document.filename || 'archivo') + ']' +
    (isPaymentDoc ? ' [POSIBLE_COMPROBANTE_PAGO]' : '');
} else if (msg.sticker) {
  type = 'text';
  content = '[Sticker]';
} else if (msg.location) {
  type = 'text';
  content = '[Ubicacion compartida]';
} else {
  type = 'text';
  content = msg.text?.body || '';
}

if (content && /bitcoin|crypto|sexo|xxx|casino|ganar dinero rapido|prestamo urgente|forex|nft/i.test(content)) isSpam = true;
const requestsHuman = /humano|agente|persona real|asesor|ejecutivo|hablar con alguien|quiero hablar/i.test(content || '');

// --- Non-actionable messages (stickers, emojis only, location) ---
const isNonActionable = /^\[Sticker\]$|^\[Ubicacion compartida\]$/.test(content) ||
  (content && content.length <= 3 && /^[\p{Emoji}\s]+$/u.test(content));

// --- Homework detection ---
const HOMEWORK_PATTERNS = /\b(haceme|hazme|resuelveme|resu(é|e)lveme|resu(é|e)lvelo|me\s+resuelves|me\s+ayudas?\s+con\s+(la|mi|esta|un|el)\s+(tarea|trabajo|ejercicio|problema|examen|prueba|guia|gu(í|i)a)|(la|mi|una|esta)\s+tarea\s+(de|para|del)|tarea\s+(de|para|del|escolar)|trabajo\s+(de|del|para)\s+(colegio|cole|escuela|liceo|universidad|u)|(escr(í|i)beme|escribeme|hazme|haceme|escr(í|i)bi)\s+(un|el|una|la)\s+(ensayo|resumen|redacci(ó|o)n|texto|carta|composici(ó|o)n)|resumen\s+(de|del|sobre)|(traduce|tradu(c|z)irme|tradu(c|z)i)\s+(esto|este|esta|al|del|en)|cu(á|a)nto\s+es\s+\d|qu(é|e)\s+es\s+(la|el|los|las)\s+(fotos(í|i)ntesis|mitosis|meiosis|c(é|e)lula|democracia|ecuaci(ó|o)n|teorema)|c(ó|o)mo\s+(se\s+escribe|escribir|hacer|resolver|calcular)|corr(í|i)geme|ej(é|e)rcicios?\s+(de|del|sobre|resueltos)|prueba\s+(de|del)\s+(matem(á|a)ticas?|lenguaje|historia|biolog(í|i)a|qu(í|i)mica|f(í|i)sica))/i;
const SCHOOL_CONTEXT = /\b(del\s+cole(gio)?|de\s+la\s+escuela|del\s+liceo|para\s+el\s+cole(gio)?|para\s+la\s+escuela|del\s+cuaderno|en\s+el\s+cuaderno|para\s+clase|de\s+clase)\b/i;
const asksHomework = HOMEWORK_PATTERNS.test(content || '') || (SCHOOL_CONTEXT.test(content || '') && /\bc(o|ó)mo\b|\bqu(e|é)\s+es\b|\bcu(a|á)l\b|\bhaz(me)?\b|\bayuda\b/i.test(content || ''));

// --- Child detection ---
const ctxt = (content || '').toLowerCase();
const childVocab = /\bhola profe\b|\bsoy\s+(un\s+)?ni(ñ|n)(o|a)\b|\btengo\s+\d{1,2}\s*(a(ñ|n)os)?\b|\bmi\s+mam(a|á)\b|\bmi\s+pap(a|á)\b|\bjaja|xd\b|\bpokemon|roblox|minecraft|fortnite|\bporfa\b|\bporfis\b|\bplisss?\b|\bdel\s+cole\b|\bmi\s+profe\b|\bmi\s+colegio\b/i.test(ctxt);
const isChild = (childVocab && ctxt.length < 200) || asksHomework;

// --- Sibling count ---
let siblingCount = 1;
const m2 = ctxt.match(/\b(dos|2|tres|3|cuatro|4)\s+(hijos|ni(ñ|n)os|ni(ñ|n)as|chicos)\b/);
if (m2) {
  const w = m2[1];
  siblingCount = { 'dos':2,'2':2,'tres':3,'3':3,'cuatro':4,'4':4 }[w] || 2;
} else if (/\bmis\s+hijos\b|\bmis\s+ni(ñ|n)os\b|\bambos\b|\blos\s+dos\b/.test(ctxt)) {
  siblingCount = 2;
}

// --- Phone normalization ---
const phoneNorm = (msg.from || '').replace(/[^0-9]/g, '');

return [{ json: {
  phone: msg.from,
  phoneNorm,
  toNumber: msg.to,
  msgId: msg.id,
  profileName: msg?.customerProfile?.name || 'Usuario',
  type, content, mediaId, audioUrl, imageUrl,
  isBusinessHours, isSpam, requestsHuman,
  isHumanTakeover: false, takeoverPhone: '',
  isStopCmd: false, isStartCmd: false, isChild, asksHomework, siblingCount,
  originalType: type,
  isNonActionable
}}];

