// Node: Leer Lead Score
// v5 (2026-05-04): mega audit fixes
// - 4-sec debounce to avoid rapid-fire OpenAI calls
// - PROBABLE_PAID instead of auto-PAID
// - Country capture from phone prefix
// - Structured child age/name storage
// - PRICE_ASKED / OBJECTION state detection
const sd = $getWorkflowStaticData('global');
if (!sd.leads) sd.leads = {};

const pm = $('Parsear Mensaje').first().json;
const phone = pm.phoneNorm || String(pm.phone || '').replace(/[^0-9]/g,'');
const now = new Date().toISOString();
const nowMs = Date.now();

if (!phone) {
  return [{ json: { Telefono: '', _stub: true } }];
}

const prev = sd.leads[phone] || {
  firstContact: now,
  messageCount: 0,
  state: 'NEW',
  followupCount: 0,
  lastFollowupAt: null,
  lastOutgoing: null,
  conversationHistory: [],
};

if (!Array.isArray(prev.conversationHistory)) prev.conversationHistory = [];

// --- DEBOUNCE: skip if last incoming was <4 sec ago ---
const lastInMs = prev.lastIncoming ? new Date(prev.lastIncoming).getTime() : 0;
const msSinceLast = nowMs - lastInMs;
if (msSinceLast < 4000 && prev.messageCount > 0) {
  console.log('[Leer Lead Score] Debounce: ' + phone + ' (' + msSinceLast + 'ms)');
  return [{ json: { Telefono: phone, phone, _debounced: true, estadoLead: prev.state, messageCount: prev.messageCount, profileName: prev.profileName || '' } }];
}

const incomingText = (pm.content || '').slice(0, 500);
if (incomingText) {
  prev.conversationHistory.push({ role: 'user', text: incomingText, at: now });
  if (prev.conversationHistory.length > 50) {
    prev.conversationHistory = prev.conversationHistory.slice(-50);
  }
}

const updated = {
  ...prev,
  phone,
  lastIncoming: now,
  messageCount: (prev.messageCount || 0) + 1,
  lastKnownText: incomingText.slice(0, 200),
  profileName: pm.profileName || prev.profileName || '',
};

// --- Country capture from phone prefix ---
if (!updated._country && phone.length >= 10) {
  const prefixMap = {
    '56': 'CL', '52': 'MX', '57': 'CO', '54': 'AR', '51': 'PE',
    '593': 'EC', '598': 'UY', '506': 'CR', '507': 'PA', '503': 'SV',
    '504': 'HN', '502': 'GT', '595': 'PY', '591': 'BO', '58': 'VE',
    '505': 'NI', '1787': 'PR', '1939': 'PR', '34': 'ES', '1': 'US',
    '809': 'DO', '829': 'DO', '849': 'DO',
  };
  for (const [prefix, country] of Object.entries(prefixMap)) {
    if (phone.startsWith(prefix)) {
      updated._country = country;
      break;
    }
  }
}

// --- Structured child data from current message ---
const txt = (incomingText || '').toLowerCase();
const ageMatch = txt.match(/(?:tiene|son|cumpl\w*)\s*(\d{1,2})\s*(?:a[ñn]os?|años)/i);
if (ageMatch && parseInt(ageMatch[1]) >= 5 && parseInt(ageMatch[1]) <= 18) {
  updated._childAge = ageMatch[1];
}
const nameMatch = txt.match(/(?:se llama|mi hij[oa]\s+(?:se llama\s+)?)([A-Z][a-záéíóúñ]{2,})/i);
if (nameMatch) {
  updated._childName = nameMatch[1];
}

// --- Clean expired pauses (>48h) ---
if (updated.BotPausado === 'SI' && updated.PausaTimestamp) {
  const pausaAge = nowMs - new Date(updated.PausaTimestamp).getTime();
  if (pausaAge > 48 * 60 * 60 * 1000) {
    updated.BotPausado = 'NO';
    if (updated.state === 'HANDOFF') updated.state = updated.state_before_handoff || 'NEW';
    console.log('[Leer Lead Score] Pausa expirada limpiada para ' + phone);
  }
}

// --- Frustration detection ---
const hist = updated.conversationHistory || [];
let consecutiveUser = 0;
for (let i = hist.length - 1; i >= 0; i--) {
  if (hist[i].role === 'user') consecutiveUser++;
  else break;
}
const FRUSTRATION_KW = /nadie|ins(o|ó)lito|incre(i|í)ble|cero confianza|no conf(i|í)o|estafa|mala atencion|mala atenci(o|ó)n|p(e|é)simo|horrible|nunca responden|no responden|botado|enga(n|ñ)o|nunca me|no contestan|desastre|me tienen esperando|cuanto mas|no es serio/i;
const isFrustrated = consecutiveUser >= 4 || FRUSTRATION_KW.test(incomingText);

if (isFrustrated && incomingText) {
  try {
    await $helpers.httpRequest({
      method: 'POST', url: 'https://api.ycloud.com/v2/whatsapp/messages',
      headers: { 'X-API-Key': 'b0bdbae389901432af2b47d9c6a4dcbe', 'Content-Type': 'application/json' },
      body: JSON.stringify({
        from: '56964754219', to: '56971360895', type: 'text',
        text: { body: '\ud83d\udea8 LEAD FRUSTRADO: ' + phone + ' (' + (updated.profileName || '?') + ')\nMsg: ' + incomingText.slice(0,200) + '\nMsgs seguidos sin resp: ' + consecutiveUser }
      })
    });
  } catch(e) { console.log('[Frustration notif] err:', e.message); }
}

// --- PAID client auto-notify operator ---
if (updated.state === 'PAID') {
  const lastEsc = updated._lastEscalationAt ? new Date(updated._lastEscalationAt).getTime() : 0;
  const minsSinceEsc = (nowMs - lastEsc) / 60000;

  if (minsSinceEsc > 30 || !updated._lastEscalationAt) {
    updated._escalationCount = (updated._escalationCount || 0) + 1;
    updated._lastEscalationAt = now;
    try {
      await $helpers.httpRequest({
        method: 'POST', url: 'https://api.ycloud.com/v2/whatsapp/messages',
        headers: { 'X-API-Key': 'b0bdbae389901432af2b47d9c6a4dcbe', 'Content-Type': 'application/json' },
        body: JSON.stringify({
          from: '56964754219', to: '56971360895', type: 'text',
          text: { body: '\ud83d\udce2 CLIENTE PAGADO escribe: ' + phone + ' (' + (updated.profileName || '?') + ')\nMsg: ' + incomingText.slice(0,200) + '\nEscalaciones: ' + updated._escalationCount }
        })
      });
    } catch(e) { console.log('[PAID client notif] err:', e.message); }
  }
}

// --- Payment detection: PROBABLE_PAID instead of auto-PAID ---
const paymentKw = /ya pagu(e|é)|ya transfer(i|í)|hice el (dep(o|ó)sito|pago)|pago realizado|listo el pago|pagu(e|é) (los|la|el)|comprobante de pago|ya hice el pago/i;
if (paymentKw.test(incomingText) && updated.state !== 'PAID' && updated.state !== 'PROBABLE_PAID') {
  updated.state_before_paid = updated.state;
  updated.state = 'PROBABLE_PAID';
  updated._probablePaidAt = now;
  console.log('[Leer Lead Score] PROBABLE_PAID detected for ' + phone);

  // Notify operator to VERIFY payment
  try {
    await $helpers.httpRequest({
      method: 'POST', url: 'https://api.ycloud.com/v2/whatsapp/messages',
      headers: { 'X-API-Key': 'b0bdbae389901432af2b47d9c6a4dcbe', 'Content-Type': 'application/json' },
      body: JSON.stringify({
        from: '56964754219', to: '56971360895', type: 'text',
        text: { body: '\ud83d\udcb0 POSIBLE PAGO: ' + phone + ' (' + (updated.profileName || '?') + ')\nMsg: ' + incomingText.slice(0,200) + '\nVERIFICA y confirma con /paidconfirm ' + phone }
      })
    });
  } catch(e) { console.log('[Payment notif] err:', e.message); }
}

// --- State enrichment: PRICE_ASKED / OBJECTION ---
if (!['PAID', 'PROBABLE_PAID', 'MUTED', 'SCHEDULED_CONFIRMED'].includes(updated.state)) {
  if (/\b(caro|mucho|no (me )?alcanza|no tengo|presupuesto|mucha plata|es mucho)\b/i.test(incomingText)) {
    updated._hasObjection = true;
    updated._objectionAt = now;
  }
  if (/\b(precio|costo|valor|cu(a|á)nto|cuesta|vale|cu(a|á)nto sale)\b/i.test(incomingText)) {
    updated._priceAsked = true;
    updated._priceAskedAt = now;
  }
}

sd.leads[phone] = updated;

return [{
  json: {
    Telefono: phone,
    phone,
    estadoLead: updated.state,
    messageCount: updated.messageCount,
    followupCount: updated.followupCount,
    lastFollowupAt: updated.lastFollowupAt,
    profileName: updated.profileName,
    _fromStaticData: true,
    _debounced: false,
    _country: updated._country || '',
  }
}];

// Node: Preparar Contexto
// v7 (2026-05-04): mega audit fixes
// - Increased history from 15 to 25
// - Fixed name regex (no more city captures)
// - Reactivation detection
// - Country + conversionStage in context
// - Structured _childAge/_childName from Leer Lead Score
const sd = $getWorkflowStaticData('global');
if (!sd.leads) sd.leads = {};

const parsed = $('Parsear Mensaje').first().json;
const phone = parsed.phone || '';
const norm = (t) => (t || '').replace(/[^0-9]/g, '');
const phoneN = norm(phone);
const lead = phoneN ? (sd.leads[phoneN] || null) : null;

let ctx = '';
let esCliente = false;

// 1. Leer esCliente de Juez
try {
  const juez = $('Juez de Tiempo').first().json;
  if (juez.esCliente === 'SI' || juez.esCliente === 'true') esCliente = true;
  if (juez.razonBloqueo) ctx += ' | RAZON_CLIENTE: ' + juez.razonBloqueo;
} catch(e) {}

// 2. estadoLead from Juez
let estadoLead = 'NUEVO';
try {
  const juez = $('Juez de Tiempo').first().json;
  if (juez.estadoLead) estadoLead = juez.estadoLead;
} catch(e) {}

ctx += ' | ESTADO_LEAD=' + estadoLead;

if (lead) {
