const msgText = (parsed.content || parsed.text || '').toLowerCase();
const norm = (t) => String(t || '').replace(/[^0-9]/g, '');
const phoneN = norm(phone);

// --- /startbot command: resume bot ---
if (parsed.isStartCmd && phoneN) {
  const sdLead = leads[phoneN];
  if (sdLead) {
    sdLead.BotPausado = 'NO';
    sdLead.PausaTimestamp = null;
    sdLead.UltimoHumanoTS = null;
