      sdLead.state = sdLead.state_before_handoff || 'NEW';
    }
    console.log('[Juez] /startbot for ' + phoneN);
  }
}

// --- isNonActionable: skip silently ---
if (parsed.isNonActionable) {
  return [{ json: {
    Telefono: phone, deboBloquear: 'SI', esCliente: 'NO',
    razonBloqueo: 'non_actionable', estadoLead: 'IGNORAR',
    esNuevo: false
  }}];
}

let rows = [];
try { rows = $('Leer Lead Score').all().map(i => i.json); } catch(e) {}
const lead = rows.find(r => norm(r.Telefono) === phoneN) || {};

const ahora = new Date();
const PAUSA_MS = 48 * 60 * 60 * 1000;

let deboBloquear = 'NO';
let esCliente = 'NO';
let razonBloqueo = '';

// CAPA 0: Check staticData for PAID or PROBABLE_PAID state
const sdLead = phoneN ? (leads[phoneN] || null) : null;
if (sdLead && (sdLead.state === 'PAID' || sdLead.state === 'PROBABLE_PAID')) {
  esCliente = 'SI';
  razonBloqueo = sdLead.state === 'PAID' ? 'staticdata_paid' : 'staticdata_probable_paid';
}

// CAPA 1: Sheet data -> cliente
if (esCliente === 'NO') {
  if ((lead.PagoDeposito || '').toUpperCase() === 'SI') {
    esCliente = 'SI'; razonBloqueo = 'deposito_pagado';
  } else if ((lead.Comprado || '').toUpperCase() === 'SI') {
    esCliente = 'SI'; razonBloqueo = 'programa_pagado';
  } else if ((lead.AlumnoActivo || '').toUpperCase() === 'SI') {
    esCliente = 'SI'; razonBloqueo = 'alumno_activo';
  }
}

// Pausa humana / handoff -> HARD BLOCK
if ((lead.BotPausado || '').toUpperCase() === 'SI' || (sdLead && sdLead.BotPausado === 'SI')) {
  const pausaTS = lead.PausaTimestamp || (sdLead && sdLead.PausaTimestamp) || null;
  if (pausaTS) {
    const pausaAge = ahora - new Date(pausaTS);
    if (pausaAge < PAUSA_MS) {
      deboBloquear = 'SI'; razonBloqueo = 'pausa_humana';
    } else {
      // Auto-clean expired pause
      if (sdLead) {
        sdLead.BotPausado = 'NO';
        if (sdLead.state === 'HANDOFF') sdLead.state = sdLead.state_before_handoff || 'NEW';
      }
    }
  }
}
if (deboBloquear === 'NO') {
  const humTS = lead.UltimoHumanoTS || (sdLead && sdLead.UltimoHumanoTS) || null;
  if (humTS) {
    const hAge = ahora - new Date(humTS);
    if (hAge < PAUSA_MS) { deboBloquear = 'SI'; razonBloqueo = 'handoff_reciente'; }
  }
}

// CAPA 2: MUTE_PHONES hardcoded
if (esCliente === 'NO' && deboBloquear === 'NO' && MUTE_PHONES.some(m => norm(m) === phoneN)) {
  esCliente = 'SI';
  if (!razonBloqueo) razonBloqueo = 'mute_hardcoded';
}

// CAPA 3: Keywords de cliente activo (require 2+ word match, not single word)
if (esCliente === 'NO' && deboBloquear === 'NO') {
  for (const kw of CLIENT_KEYWORDS) {
    if (msgText.includes(kw)) {
      esCliente = 'SI';
      razonBloqueo = 'keyword_cliente_activo';
      break;
    }
  }
}

// Derivar estadoLead
let estadoLead = 'NUEVO';
if (sdLead && sdLead.state === 'PAID') estadoLead = 'PROGRAMA_PAGADO';
else if (sdLead && sdLead.state === 'PROBABLE_PAID') estadoLead = 'PROBABLE_PAGADO';
else if ((lead.PagoDeposito || '').toUpperCase() === 'SI') estadoLead = 'DEPOSITO_PAGADO';
else if ((lead.Comprado || '').toUpperCase() === 'SI') estadoLead = 'PROGRAMA_PAGADO';
else if ((lead.AlumnoActivo || '').toUpperCase() === 'SI') estadoLead = 'ALUMNO_ACTIVO';
else if ((lead.AgendoDemo || '').toUpperCase() === 'SI') {
  const fechaEval = lead.FechaEvaluacion ? new Date(lead.FechaEvaluacion) : null;
  if (fechaEval && fechaEval < ahora) estadoLead = 'POST_EVALUACION';
  else estadoLead = 'AGENDO_SIN_DEPOSITO';
}
else if (parseInt(lead.TotalMensajes) > 0 || (sdLead && (sdLead.messageCount || 0) > 1)) estadoLead = 'CONTACTADO';

if (esCliente === 'SI' && estadoLead === 'NUEVO') estadoLead = 'ALUMNO_ACTIVO';

return [{ json: {
  ...lead,
  Telefono: phone,
  deboBloquear,
  esCliente,
  razonBloqueo,
  estadoLead,
  esNuevo: !lead.Telefono && (!sdLead || (sdLead.messageCount || 0) <= 1)
}}];

