// Node: Post-Envio
// v5 (2026-05-04): mega audit fixes
// - conversionStage based on current msg, not full history
// - Exposed conversionStage in output
const sd = $getWorkflowStaticData('global');
if (!sd.leads) sd.leads = {};

const pm = $('Parsear Mensaje').first().json;
const phone = pm.phoneNorm || String(pm.phone || '').replace(/[^0-9]/g,'');

let outMsg = '';
try { outMsg = $('Preparar Respuesta').first().json.output || ''; } catch(e) {}

const LINK_PATTERNS = [/calendly\.com/i, /reunion-informativa-innovakids/i];
const linkSent = LINK_PATTERNS.some(rx => rx.test(outMsg));

// Detect escalation in bot response
const escalationMentioned = /ricardo|equipo|te (va a |van a )?responde|te contacta|30 minutos|te escrib/i.test(outMsg);

let conversionStage = 'new';

if (phone && sd.leads[phone]) {
  const now = new Date().toISOString();
  const lead = sd.leads[phone];
  lead.lastOutgoing = now;

  // Append outgoing to history
  if (!Array.isArray(lead.conversationHistory)) lead.conversationHistory = [];
  if (outMsg) {
    lead.conversationHistory.push({ role: 'assistant', text: outMsg.slice(0, 500), at: now });
    if (lead.conversationHistory.length > 50) {
      lead.conversationHistory = lead.conversationHistory.slice(-50);
    }
  }

  // LINK_SENT
  if (linkSent && !['PAID', 'PROBABLE_PAID', 'MUTED', 'SCHEDULED_CONFIRMED'].includes(lead.state)) {
    lead.state = 'LINK_SENT';
    lead.linkSentAt = now;
  }

  // Track escalation
  if (escalationMentioned) {
    lead._escalationCount = (lead._escalationCount || 0) + 1;
    lead._lastEscalationAt = now;

    try {
      await $helpers.httpRequest({
        method: 'POST', url: 'https://api.ycloud.com/v2/whatsapp/messages',
        headers: { 'X-API-Key': 'b0bdbae389901432af2b47d9c6a4dcbe', 'Content-Type': 'application/json' },
        body: JSON.stringify({
          from: '56964754219', to: '56971360895', type: 'text',
          text: { body: '\ud83d\udd14 Bot escalo a humano: ' + phone + ' (' + (lead.profileName || '?') + ')\nBot dijo: ' + outMsg.slice(0,200) }
        })
      });
    } catch(e) {}
  }

  // Conversion stage based on CURRENT state (not accumulated history)
  const currentMsgText = (pm.content || '').toLowerCase();
  if (lead.state === 'PAID' || lead.state === 'PROBABLE_PAID') conversionStage = 'paid';
  else if (lead.state === 'SCHEDULED_CONFIRMED') conversionStage = 'scheduled';
  else if (linkSent || lead.state === 'LINK_SENT') conversionStage = 'link_sent';
  else if (/precio|costo|cuanto|cuesta/i.test(currentMsgText)) conversionStage = 'price_asked';
  else if ((lead.messageCount || 0) > 2) conversionStage = 'engaged';

  lead._conversionStage = conversionStage;
}

// Expose conversionStage in output (was missing before)
const items = $input.all();
return items.map(item => ({
  json: {
    ...item.json,
    _conversionStage: conversionStage
  }
}));

