if (!Array.isArray(sd.mutedPhones)) sd.mutedPhones = [];

const body = $input.first().json.body || $input.first().json;
const action = (body.action || '').toLowerCase();
const phone  = String(body.phone || '').replace(/[^0-9]/g, '');
const now = new Date().toISOString();

let result = '';
if (!phone) {
  result = 'ERROR: phone requerido';
} else if (action === 'add') {
  if (!sd.mutedPhones.includes(phone)) {
    sd.mutedPhones.push(phone);
    result = 'MUTED: ' + phone;
  } else {
    result = 'YA_MUTED: ' + phone;
  }
} else if (action === 'remove') {
  sd.mutedPhones = sd.mutedPhones.filter(p => p !== phone);
  result = 'UNMUTED: ' + phone;
} else if (action === 'list') {
  result = 'LISTA: ' + sd.mutedPhones.join(', ');
} else {
  result = 'ERROR: action debe ser add|remove|list';
}

// Guardar en Sheets como log
try {
  await $helpers.httpRequest({
    method: 'POST', url: SHEET_URL,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      fecha: now, telefono: phone, nombre: '', pais: '', estado: action.toUpperCase(),
      mensaje: '[MUTE MANAGER: ' + result + ']',
      rol: 'sistema', por_que_llego: '', intereses: '', edad_hijo: '', fuente: 'mute_manager'
    })
  });
} catch(e) { console.log('[Gestionar Mutes] Sheets err:', e.message); }

console.log('[Gestionar Mutes]', result, '| Lista actual:', sd.mutedPhones.length, 'numeros');
return [{ json: { ok: true, result, mutedPhones: sd.mutedPhones } }];
